import{_ as g,C as o,o as l,c as f,a5 as a,b as d,w as e,a as s,E as r,a4 as i}from"./chunks/framework.sOZL8giL.js";const C=JSON.parse('{"title":"Agent 基础速查","description":"","frontmatter":{},"headers":[],"relativePath":"03-Agent基础/速查.md","filePath":"03-Agent基础/速查.md","lastUpdated":null}'),x={name:"03-Agent基础/速查.md"};function y(h,t,A,E,b,B){const n=o("Mermaid");return l(),f("div",null,[t[2]||(t[2]=a('<h1 id="agent-基础速查" tabindex="-1">Agent 基础速查 <a class="header-anchor" href="#agent-基础速查" aria-label="Permalink to &quot;Agent 基础速查&quot;">​</a></h1><blockquote><p>快速查阅 Agent 等级、推理模式选择和记忆架构决策。</p></blockquote><hr><h2 id="一、agent-等级速查-l0-l5" tabindex="-1">一、Agent 等级速查（L0-L5） <a class="header-anchor" href="#一、agent-等级速查-l0-l5" aria-label="Permalink to &quot;一、Agent 等级速查（L0-L5）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">等级</th><th style="text-align:left;">名称</th><th style="text-align:left;">核心特征</th><th style="text-align:left;">典型场景</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>L0</strong></td><td style="text-align:left;">传统软件</td><td style="text-align:left;">确定性逻辑，输入 A 必然输出 B</td><td style="text-align:left;"><code>if-else</code>、规则引擎</td></tr><tr><td style="text-align:center;"><strong>L1</strong></td><td style="text-align:left;">Prompt + Tool</td><td style="text-align:left;">单次调用 + 工具调用，无自主循环</td><td style="text-align:left;">翻译、总结、简单问答</td></tr><tr><td style="text-align:center;"><strong>L2</strong></td><td style="text-align:left;">ReAct Agent</td><td style="text-align:left;">思考 → 行动 → 观察，自主循环</td><td style="text-align:left;">信息检索、简单任务执行</td></tr><tr><td style="text-align:center;"><strong>L3</strong></td><td style="text-align:left;">Planning Agent</td><td style="text-align:left;">任务分解、依赖管理、多步骤执行</td><td style="text-align:left;">研究报告、复杂数据分析</td></tr><tr><td style="text-align:center;"><strong>L4</strong></td><td style="text-align:left;">Reflection Agent</td><td style="text-align:left;">自我评估、反馈循环、迭代改进</td><td style="text-align:left;">代码审查、高质量内容生成</td></tr><tr><td style="text-align:center;"><strong>L5</strong></td><td style="text-align:left;">Multi-Agent</td><td style="text-align:left;">多 Agent 协作、分工、编排</td><td style="text-align:left;">战略分析、端到端项目</td></tr></tbody></table><h3 id="判断该用哪一级" tabindex="-1">判断该用哪一级 <a class="header-anchor" href="#判断该用哪一级" aria-label="Permalink to &quot;判断该用哪一级&quot;">​</a></h3>',6)),(l(),d(i,null,{default:e(()=>[r(n,{id:"mermaid-119",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E4%BD%A0%E7%9A%84%E4%BB%BB%E5%8A%A1%5D%20--%3E%20B%7B%E6%AD%A5%E9%AA%A4%E6%98%AF%E5%90%A6%E6%98%8E%E7%A1%AE%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E6%98%AF%EF%BC%8C%E5%8D%95%E6%AD%A5%E5%8F%AF%E5%AE%8C%E6%88%90%7C%20L1%5BL1%3A%20Prompt%20%2B%20Tool%5D%0A%20%20%20%20B%20--%3E%7C%E5%90%A6%EF%BC%8C%E9%9C%80%E8%A6%81%E5%A4%9A%E6%AD%A5%7C%20C%7B%E6%AD%A5%E9%AA%A4%E6%98%AF%E5%90%A6%E5%8F%AF%E6%8F%90%E5%89%8D%E8%A7%84%E5%88%92%EF%BC%9F%7D%0A%20%20%20%20C%20--%3E%7C%E6%98%AF%7C%20L3%5BL3%3A%20Planning%20Agent%5D%0A%20%20%20%20C%20--%3E%7C%E5%90%A6%EF%BC%8C%E9%9C%80%E5%8A%A8%E6%80%81%E8%B0%83%E6%95%B4%7C%20D%7B%E6%98%AF%E5%90%A6%E9%9C%80%E8%A6%81%E9%AB%98%E8%B4%A8%E9%87%8F%E8%BE%93%E5%87%BA%EF%BC%9F%7D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20L2%5BL2%3A%20ReAct%20Agent%5D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20E%7B%E5%8D%95%20Agent%20%E8%83%BD%E5%90%A6%E5%A4%84%E7%90%86%EF%BC%9F%7D%0A%20%20%20%20E%20--%3E%7C%E6%98%AF%7C%20L4%5BL4%3A%20Reflection%20Agent%5D%0A%20%20%20%20E%20--%3E%7C%E5%90%A6%EF%BC%8C%E9%9C%80%E8%A6%81%E5%A4%9A%E9%A2%86%E5%9F%9F%E5%8D%8F%E4%BD%9C%7C%20L5%5BL5%3A%20Multi-Agent%5D%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=a('<hr><h2 id="二、推理模式速查" tabindex="-1">二、推理模式速查 <a class="header-anchor" href="#二、推理模式速查" aria-label="Permalink to &quot;二、推理模式速查&quot;">​</a></h2><h3 id="什么时候用-react-vs-planning-vs-reflection" tabindex="-1">什么时候用 ReAct vs Planning vs Reflection？ <a class="header-anchor" href="#什么时候用-react-vs-planning-vs-reflection" aria-label="Permalink to &quot;什么时候用 ReAct vs Planning vs Reflection？&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">ReAct</th><th style="text-align:left;">Planning</th><th style="text-align:left;">Reflection</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>核心机制</strong></td><td style="text-align:left;">思考→行动→观察 循环</td><td style="text-align:left;">任务分解→排序→执行</td><td style="text-align:left;">生成→评估→反馈→改进</td></tr><tr><td style="text-align:left;"><strong>适合任务</strong></td><td style="text-align:left;">探索性、步骤不确定的任务</td><td style="text-align:left;">复杂、多步骤、依赖关系明确的任务</td><td style="text-align:left;">需要高质量输出、有明确评估标准的任务</td></tr><tr><td style="text-align:left;"><strong>优势</strong></td><td style="text-align:left;">灵活、可纠正、可追溯</td><td style="text-align:left;">结构清晰、可并行、可追踪</td><td style="text-align:left;">提高下限、减少明显错误</td></tr><tr><td style="text-align:left;"><strong>劣势</strong></td><td style="text-align:left;">可能陷入死循环</td><td style="text-align:left;">分解粒度难把握</td><td style="text-align:left;">成本翻倍、不保证改进</td></tr><tr><td style="text-align:left;"><strong>典型场景</strong></td><td style="text-align:left;">信息检索、故障排查</td><td style="text-align:left;">研究报告、数据处理流水线</td><td style="text-align:left;">代码生成、文档撰写</td></tr></tbody></table><h3 id="react-详解" tabindex="-1">ReAct 详解 <a class="header-anchor" href="#react-详解" aria-label="Permalink to &quot;ReAct 详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">要素</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>循环结构</strong></td><td style="text-align:left;">Reason（思考）→ Act（行动）→ Observe（观察）→ 循环</td></tr><tr><td style="text-align:left;"><strong>解决的问题</strong></td><td style="text-align:left;">信息过时（可以去查）、无法验证（做完再检查）、无法追溯（每步有记录）</td></tr><tr><td style="text-align:left;"><strong>关键约束</strong></td><td style="text-align:left;">需要预算上限、终止条件、验收机制（否则可能死循环）</td></tr><tr><td style="text-align:left;"><strong>生产底线</strong></td><td style="text-align:left;">ReAct 不是正确保证，预算 + 终止 + 验收才是真正的底线</td></tr></tbody></table><h3 id="planning-详解" tabindex="-1">Planning 详解 <a class="header-anchor" href="#planning-详解" aria-label="Permalink to &quot;Planning 详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">要素</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>三个核心问题</strong></td><td style="text-align:left;">① 如何分解？② 如何执行（并行/串行）？③ 何时停止？</td></tr><tr><td style="text-align:left;"><strong>最容易忽视</strong></td><td style="text-align:left;">第三个问题——不知道什么时候该停，导致无限循环</td></tr><tr><td style="text-align:left;"><strong>分解原则</strong></td><td style="text-align:left;">能画出流程图 → 用工作流；画不出来 → 考虑多 Agent</td></tr><tr><td style="text-align:left;"><strong>执行策略</strong></td><td style="text-align:left;">有依赖 → 串行；无依赖 → 并行；混合 → DAG</td></tr></tbody></table><h3 id="reflection-详解" tabindex="-1">Reflection 详解 <a class="header-anchor" href="#reflection-详解" aria-label="Permalink to &quot;Reflection 详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">要素</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>核心组件</strong></td><td style="text-align:left;">质量评估 → 反馈生成 → 带反馈重生成</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">高价值输出、可客观评估的任务、迭代改进</td></tr><tr><td style="text-align:left;"><strong>本质</strong></td><td style="text-align:left;">锦上添花，不是核心依赖——不能让烂回答变好</td></tr><tr><td style="text-align:left;"><strong>成本</strong></td><td style="text-align:left;">约 2 倍调用成本（生成 + 评估 + 可能的重生成）</td></tr></tbody></table><hr><h2 id="三、记忆架构选择速查" tabindex="-1">三、记忆架构选择速查 <a class="header-anchor" href="#三、记忆架构选择速查" aria-label="Permalink to &quot;三、记忆架构选择速查&quot;">​</a></h2><h3 id="记忆类型对比" tabindex="-1">记忆类型对比 <a class="header-anchor" href="#记忆类型对比" aria-label="Permalink to &quot;记忆类型对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">时间跨度</th><th style="text-align:left;">存储方式</th><th style="text-align:left;">适用场景</th><th style="text-align:left;">选择标准</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>工作记忆</strong></td><td style="text-align:left;">秒-分钟级</td><td style="text-align:left;">上下文窗口</td><td style="text-align:left;">正在处理的任务</td><td style="text-align:left;">所有 Agent 必需</td></tr><tr><td style="text-align:left;"><strong>会话记忆</strong></td><td style="text-align:left;">分钟-小时级</td><td style="text-align:left;">Redis 缓存</td><td style="text-align:left;">单次对话历史</td><td style="text-align:left;">需要多轮交互的场景</td></tr><tr><td style="text-align:left;"><strong>长期记忆</strong></td><td style="text-align:left;">天-月级</td><td style="text-align:left;">PostgreSQL</td><td style="text-align:left;">用户偏好、成功模式</td><td style="text-align:left;">需要跨会话个性化</td></tr><tr><td style="text-align:left;"><strong>语义记忆</strong></td><td style="text-align:left;">永久</td><td style="text-align:left;">向量数据库</td><td style="text-align:left;">相关历史问答、知识库</td><td style="text-align:left;">需要语义相似度检索</td></tr></tbody></table><h3 id="记忆架构选择决策" tabindex="-1">记忆架构选择决策 <a class="header-anchor" href="#记忆架构选择决策" aria-label="Permalink to &quot;记忆架构选择决策&quot;">​</a></h3>',15)),(l(),d(i,null,{default:e(()=>[r(n,{id:"mermaid-465",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E9%9C%80%E8%A6%81%E8%AE%B0%E5%BF%86%E5%90%97%EF%BC%9F%5D%20--%3E%20B%7B%E6%97%B6%E9%97%B4%E8%B7%A8%E5%BA%A6%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E4%BB%85%E5%BD%93%E5%89%8D%E5%AF%B9%E8%AF%9D%7C%20C%5B%E4%BC%9A%E8%AF%9D%E8%AE%B0%E5%BF%86%EF%BC%9ARedis%20%E7%BC%93%E5%AD%98%5D%0A%20%20%20%20B%20--%3E%7C%E8%B7%A8%E4%BC%9A%E8%AF%9D%7C%20D%7B%E6%9F%A5%E8%AF%A2%E6%96%B9%E5%BC%8F%EF%BC%9F%7D%0A%20%20%20%20D%20--%3E%7C%E7%B2%BE%E7%A1%AE%E6%9F%A5%E8%AF%A2%7C%20E%5B%E9%95%BF%E6%9C%9F%E8%AE%B0%E5%BF%86%EF%BC%9APostgreSQL%5D%0A%20%20%20%20D%20--%3E%7C%E8%AF%AD%E4%B9%89%E7%9B%B8%E4%BC%BC%7C%20F%5B%E8%AF%AD%E4%B9%89%E8%AE%B0%E5%BF%86%EF%BC%9A%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93%5D%0A%20%20%20%20D%20--%3E%7C%E4%B8%A4%E8%80%85%E9%83%BD%E9%9C%80%E8%A6%81%7C%20G%5B%E4%B8%89%E5%B1%82%E6%9E%B6%E6%9E%84%EF%BC%9APG%20%2B%20Redis%20%2B%20Qdrant%5D%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=a(`<h3 id="三层存储架构" tabindex="-1">三层存储架构 <a class="header-anchor" href="#三层存储架构" aria-label="Permalink to &quot;三层存储架构&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">存储</th><th style="text-align:left;">职责</th><th style="text-align:left;">典型数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>PostgreSQL</strong></td><td style="text-align:left;">ACID 事务数据</td><td style="text-align:left;">执行历史、审计日志、用户偏好</td></tr><tr><td style="text-align:left;"><strong>Redis</strong></td><td style="text-align:left;">热数据缓存（毫秒级）</td><td style="text-align:left;">活跃会话、Token 预算、速率限制</td></tr><tr><td style="text-align:left;"><strong>Qdrant</strong></td><td style="text-align:left;">向量相似度搜索</td><td style="text-align:left;">语义记忆、压缩摘要、文档分块</td></tr></tbody></table><h3 id="另一种选择-本地文件存储" tabindex="-1">另一种选择：本地文件存储 <a class="header-anchor" href="#另一种选择-本地文件存储" aria-label="Permalink to &quot;另一种选择：本地文件存储&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方案</th><th style="text-align:left;">优势</th><th style="text-align:left;">劣势</th><th style="text-align:left;">适合谁</th></tr></thead><tbody><tr><td style="text-align:left;">本地文件（CLAUDE.md 等）</td><td style="text-align:left;">零部署、Git 友好、隐私</td><td style="text-align:left;">语义检索弱、多设备同步难</td><td style="text-align:left;">单机开发者工具</td></tr><tr><td style="text-align:left;">服务器端存储</td><td style="text-align:left;">多租户、语义检索强</td><td style="text-align:left;">需要部署、数据在云端</td><td style="text-align:left;">企业级多租户应用</td></tr></tbody></table><hr><h2 id="四、agent-四大核心组件速查" tabindex="-1">四、Agent 四大核心组件速查 <a class="header-anchor" href="#四、agent-四大核心组件速查" aria-label="Permalink to &quot;四、Agent 四大核心组件速查&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent = 大脑 + 手脚 + 记忆 + 主见</span></span>
<span class="line"><span>       (LLM)  (Tools) (Memory) (Autonomy)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><table tabindex="0"><thead><tr><th style="text-align:left;">组件</th><th style="text-align:left;">职责</th><th style="text-align:left;">没有会怎样</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大脑 (LLM)</strong></td><td style="text-align:left;">思考，决定下一步</td><td style="text-align:left;">没有智能，只是死板脚本</td></tr><tr><td style="text-align:left;"><strong>手脚 (Tools)</strong></td><td style="text-align:left;">执行，搜索/读写/调用 API</td><td style="text-align:left;">只能聊天，不能做事</td></tr><tr><td style="text-align:left;"><strong>记忆 (Memory)</strong></td><td style="text-align:left;">记住之前发生了什么</td><td style="text-align:left;">每次从零开始，效率极低</td></tr><tr><td style="text-align:left;"><strong>主见 (Autonomy)</strong></td><td style="text-align:left;">自己做决定</td><td style="text-align:left;">只是 Chatbot，不是 Agent</td></tr></tbody></table><h3 id="生产环境的第五层-护栏-guardrails" tabindex="-1">生产环境的第五层：护栏（Guardrails） <a class="header-anchor" href="#生产环境的第五层-护栏-guardrails" aria-label="Permalink to &quot;生产环境的第五层：护栏（Guardrails）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">护栏类型</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>预算</strong></td><td style="text-align:left;">Token 消耗上限</td></tr><tr><td style="text-align:left;"><strong>权限</strong></td><td style="text-align:left;">操作范围限制</td></tr><tr><td style="text-align:left;"><strong>审批</strong></td><td style="text-align:left;">关键操作需要人工确认</td></tr><tr><td style="text-align:left;"><strong>审计</strong></td><td style="text-align:left;">全过程可追溯</td></tr><tr><td style="text-align:left;"><strong>沙箱</strong></td><td style="text-align:left;">隔离执行环境</td></tr></tbody></table><hr><h2 id="五、agent-与传统软件对比" tabindex="-1">五、Agent 与传统软件对比 <a class="header-anchor" href="#五、agent-与传统软件对比" aria-label="Permalink to &quot;五、Agent 与传统软件对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">传统软件</th><th style="text-align:left;">Agent</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>确定性</strong></td><td style="text-align:left;">确定性：给定输入 A，必然产出 B</td><td style="text-align:left;">概率性：给定输入 A，可能产出 B 或 C</td></tr><tr><td style="text-align:left;"><strong>灵活性</strong></td><td style="text-align:left;">低——按固定逻辑执行</td><td style="text-align:left;">高——能自主调整策略</td></tr><tr><td style="text-align:left;"><strong>可预测性</strong></td><td style="text-align:left;">高</td><td style="text-align:left;">低（每次运行路径可能不同）</td></tr><tr><td style="text-align:left;"><strong>调试方式</strong></td><td style="text-align:left;">调试代码</td><td style="text-align:left;">调试环境——&quot;环境里缺了什么导致 Agent 犯错？&quot;</td></tr><tr><td style="text-align:left;"><strong>错误来源</strong></td><td style="text-align:left;">代码 bug</td><td style="text-align:left;">环境缺失（工具、上下文、约束）</td></tr></tbody></table><hr><h2 id="六、chain-of-thought-速查" tabindex="-1">六、Chain-of-Thought 速查 <a class="header-anchor" href="#六、chain-of-thought-速查" aria-label="Permalink to &quot;六、Chain-of-Thought 速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">CoT 类型</th><th style="text-align:left;">做法</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Zero-shot CoT</strong></td><td style="text-align:left;">Prompt 中加&quot;Let&#39;s think step by step&quot;</td><td style="text-align:left;">简单推理任务</td></tr><tr><td style="text-align:left;"><strong>Few-shot CoT</strong></td><td style="text-align:left;">提供推理示例</td><td style="text-align:left;">需要特定推理模式</td></tr><tr><td style="text-align:left;"><strong>Tree-of-Thoughts</strong></td><td style="text-align:left;">多条推理路径并行探索</td><td style="text-align:left;">复杂决策、需要多视角</td></tr></tbody></table><hr><h2 id="七、常见问题速查" tabindex="-1">七、常见问题速查 <a class="header-anchor" href="#七、常见问题速查" aria-label="Permalink to &quot;七、常见问题速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">原因</th><th style="text-align:left;">解法</th></tr></thead><tbody><tr><td style="text-align:left;">Agent 死循环</td><td style="text-align:left;">没有终止条件</td><td style="text-align:left;">设置最大轮次 + Token 预算上限</td></tr><tr><td style="text-align:left;">Agent 偏离目标</td><td style="text-align:left;">目标漂移</td><td style="text-align:left;">用文件记录计划，定期读回检查</td></tr><tr><td style="text-align:left;">Agent 调用错误工具</td><td style="text-align:left;">工具设计不匹配模型能力</td><td style="text-align:left;">Seeing Like an Agent，简化工具接口</td></tr><tr><td style="text-align:left;">输出质量不稳定</td><td style="text-align:left;">LLM 概率性</td><td style="text-align:left;">引入 Reflection 模式</td></tr><tr><td style="text-align:left;">长对话质量下降</td><td style="text-align:left;">上下文腐烂</td><td style="text-align:left;">上下文工程（卸载/缩减/隔离）</td></tr></tbody></table>`,19))])}const u=g(x,[["render",y]]);export{C as __pageData,u as default};
